 localparam ADDR_1 = 32'h00000001; 
 localparam ADDR_2 = 32'h00000002; 
 always @ (posedge clk) begin 
  if (rst) begin 
  o_wbs_dat <= 32'h0; 
  o_wbs_ack <= 0; 
  o_wbs_int <= 0; 
