module rtlpp_08205
(
    input clk,
    input rst_n,
    input [7:0] seg, 
    input [5:0] sel, 
    output reg shcp, 
    output reg stcp, 
    output reg ds, 
    output oe 
);

    reg [1:0] cnt;
    reg [3:0] cnt_bit;

    wire [13:0] data;

    assign data = {seg[7:0], sel[5:0]};

    always @ (posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 2'b0;
            cnt_bit <= 4'b0;
            ds <= 1'b0;
            shcp <= 1'b0;
            stcp <= 1'b0;
        end else begin
            cnt <= cnt + 2'h1;

            if (cnt == 2'h3) begin
                if (cnt_bit == 4'hd)
                    cnt_bit <= 4'h0;
                else
                    cnt_bit <= cnt_bit + 4'h1;
            end

            if (cnt == 2'b0)
                ds <= data[cnt_bit];

            if (cnt == 2'h2)
                shcp <= 1'b1;
            else if (cnt == 2'h0)
                shcp <= 1'b0;

            if (cnt == 2'h0 && cnt_bit == 4'h0)
                stcp <= 1'b1;
            else if (cnt == 2'h2 && cnt_bit == 4'h0)
                stcp <= 1'b0;
        end
    end

    assign oe = 1'b0;

endmodule

