module autovcoder_095063 (
    input [7:0] data_i,
    output zero_o,
    output [7:0] data_o,
    output [2:0] data_enc
);

  wire [7:0] z;
  wire [1:0] zdet;
  wire [1:0] select;
  //*****************************************
  // Zero detection logic:
  //*****************************************
  assign zdet[1] = |(data_i[7:4]);
  assign zdet[0] = |(data_i[3]);
  assign zero_o  = ~(zdet[1] | zdet[0]);
  //*****************************************
  // LODs:
  //*****************************************
  LOD4 lod2_1 (
      .data_i(data_i[7:4]),
      .data_o(z[7:4])
  );
  assign z[3] = data_i[3];
  //*****************************************
  // Select signals
  //*****************************************    
  LOD2 Middle (
      .data_i(zdet),
      .data_o(select)
  );

  //*****************************************
  // Multiplexers :
  //*****************************************
  wire [7:0] tmp_out;


  Muxes2in1Array4 Inst_MUX214_1 (
      .data_i  (z[7:4]),
      .select_i(select[1]),
      .data_o  (tmp_out[7:4])
  );

  assign tmp_out[3]   = select[0] & z[3];
  assign tmp_out[2:0] = 3'b0;

  // Enconding
  wire [2:0] low_enc;
  assign low_enc = tmp_out[3:1] | tmp_out[7:5];

  assign data_enc[2] = select[1];
  assign data_enc[1] = low_enc[2] | low_enc[1];
  assign data_enc[0] = low_enc[2] | low_enc[0];


  // One hot
  assign data_o = tmp_out;


endmodule

