module origen_067965(
    input x0, x1, x2, x3,
    output z0, z1, z2, z3, z4, z5, z6, z7, z8, z9
);

    wire new_n15_, new_n16_, new_n17_, new_n18_, new_n19_, new_n20_, new_n21_;
    wire new_n22_, new_n23_, new_n24_, new_n25_, new_n26_, new_n27_, new_n28_;
