    //Clock and reset signals 
    input pclkens,
    input pclks,
    input presetsn,
    //APB3 Bus 
    input [31:0] paddrs,
    input [31:0] pwdatas,
    input pwrites,
    input penables,
    input psels,
    output [31:0] prdatas,
    output pslverrs,
    output preadys,
    // Master Interface 
    //Clock and reset signals 
    input pclkenm,
    input pclkm,
    input presetmn,
    //APB3 Bus 
    output [31:0] paddrm,
    output [31:0] pwdatam,
    output pwritem,
    output penablem,
    output pselm,
    input [31:0] prdatam,
    input pslverrm,
    input preadym
