  wire apb_req_async;
  wire apb_ack_async;
  wire [64:0] apb_fwd_data_async;
  wire [32:0] apb_rev_data_async;

  //---------------------------------------------------------------------------- 
  // Start of code 
  //---------------------------------------------------------------------------- 

