module autovcoder_072361 #(
    parameter DATA_BITS  = 8,
              DEPTH      = 16,
              DEPTH_BITS = 4
) (
    input  wire                 sclk,
    input  wire                 reset,
    input  wire                 sclk_en,
    output reg                  empty_n,
    output reg                  full_n,
    input  wire                 rdreq,
    input  wire                 wrreq,
    output reg  [DATA_BITS-1:0] q,
    input  wire [DATA_BITS-1:0] data
);
  //------------------------Parameter----------------------

  //------------------------Local signal-------------------
  wire                  push;
  wire                  pop;
  wire                  full_cond;
  reg                   data_vld;
  reg  [DEPTH_BITS-1:0] pout;
  reg  [ DATA_BITS-1:0] mem       [0:DEPTH-1];
  //------------------------Body---------------------------
  assign push = full_n & wrreq;
  assign pop  = data_vld & (~(empty_n & ~rdreq));
  generate
    if (DEPTH >= 2) begin
      assign full_cond = push && ~pop && pout == DEPTH - 2 && data_vld;
    end else begin
      assign full_cond = push && ~pop;
    end
  endgenerate

  // q
  always @(posedge sclk) begin
    if (reset) q <= 0;
    else if (sclk_en) begin
      if (~(empty_n & ~rdreq)) q <= mem[pout];
    end
  end

  // empty_n
  always @(posedge sclk) begin
    if (reset) empty_n <= 1'b0;
    else if (sclk_en) begin
      if (~(empty_n & ~rdreq)) empty_n <= data_vld;
    end
  end

  // data_vld
  always @(posedge sclk) begin
    if (reset) data_vld <= 1'b0;
    else if (sclk_en) begin
      if (push) data_vld <= 1'b1;
      else if (~push && pop && pout == 1'b0) data_vld <= 1'b0;
    end
  end

  // full_n
  always @(posedge sclk) begin
    if (reset) full_n <= 1'b1;
    else if (sclk_en) begin
      if (pop) full_n <= 1'b1;
      else if (full_cond) full_n <= 1'b0;
    end
  end

  // pout
  always @(posedge sclk) begin
    if (reset) pout <= 1'b0;
    else if (sclk_en) begin
      if (push & ~pop & data_vld) pout <= pout + 1'b1;
      else if (~push && pop && pout != 1'b0) pout <= pout - 1'b1;
    end
  end

  integer i;
  always @(posedge sclk) begin
    if (sclk_en) begin
      if (push) begin
        for (i = 0; i < DEPTH - 1; i = i + 1) begin
          mem[i+1] <= mem[i];
        end
        mem[0] <= data;
      end
    end
  end
endmodule

