module autovcoder_018837 (
    cbit,
    sp4_out,
    bl,
    pgate,
    prog,
    reset,
    slfop,
    vdd_cntl,
    wl
);


  input prog, slfop;

  output [4:0] sp4_out;
  output [7:5] cbit;

  inout [3:0] bl;

  input [1:0] vdd_cntl;
  input [1:0] pgate;
  input [1:0] reset;
  input [1:0] wl;
  supply1 vdd_;
  supply0 gnd_;
  /* //////////////wire vddp_ = test.cds_globalsInst.vddp_; */ supply1 vddp_;
  supply0 GND_;
  supply1 VDD_;

  // Buses in the design

  wire [7:0] cbitb;

  wire [1:0] r_vdd;

  wire [7:0] cbit_int;
  assign cbit[7:5] = cbit_int[7:5];



