module autovcoder_096426 (
    input [2:0] KEY,
    input CLOCK_50,
    input [9:0] SW,
    output [9:0] LEDR,
    output [0:6] HEX0,
    HEX1,
    HEX2,
    HEX3,
    HEX4,
    HEX5
);
  wire c0, c1, c2, c3, c4, c5;
  wire [3:0] h0, h1, h2, h4;
  wire [2:0] h3, h5;
  delay_10_ms del (
      CLOCK_50,
      c0
  );
  counter_modulo_k_aload #(10) counter0 (
      c0,
      KEY[2],
      KEY[0],
      ~KEY[1],
      SW[3:0],
      h0,
      c1
  );
  counter_modulo_k_aload #(10) counter1 (
      ~c1,
      KEY[2],
      1'b1,
      ~KEY[1],
      SW[7:4],
      h1,
      c2
  );
  counter_modulo_k #(10) counter2 (
      ~c2,
      KEY[2],
      1'b1,
      h2,
      c3
  );
  counter_modulo_k #(6) counter3 (
      ~c3,
      KEY[2],
      1'b1,
      h3,
      c4
  );
  counter_modulo_k #(10) counter4 (
      ~c4,
      KEY[2],
      1'b1,
      h4,
      c5
  );
  counter_modulo_k #(6) counter5 (
      ~c5,
      KEY[2],
      1'b1,
      h5,
      c6
  );
  decoder_hex_10 d0 (
      h0,
      HEX0
  );
  decoder_hex_10 d1 (
      h1,
      HEX1
  );
  decoder_hex_10 d2 (
      h2,
      HEX2
  );
  decoder_hex_10 d3 (
      {1'b0, h3},
      HEX3
  );
  decoder_hex_10 d4 (
      h4,
      HEX4
  );
  decoder_hex_10 d5 (
      {1'b0, h5},
      HEX5
  );
  assign LEDR = SW;
endmodule

