    always @(*) begin
        case(instr_op_i)
            6'b000000: begin // R-type instructions
                RegWrite_o = 1'b1;
                ALU_op_o = 3'b010;
                ALUSrc_o = 1'b0;
                RegDst_o = 1'b1;
                Branch_o = 2'b00;
                SignExtend_o = 1'b0;
                MemRead_o = 1'b0;
                MemWrite_o = 1'b0;
                MemtoReg_o = 1'b0;
            end
            6'b001000: begin // ADDI
                RegWrite_o = 1'b1;
                ALU_op_o = 3'b000;
                ALUSrc_o = 1'b1;
                RegDst_o = 1'b0;
                Branch_o = 2'b00;
                SignExtend_o = 1'b1;
                MemRead_o = 1'b0;
                MemWrite_o = 1'b0;
                MemtoReg_o = 1'b0;
            end
            6'b000100: begin // BEQ
                RegWrite_o = 1'b0;
                ALU_op_o = 3'b001;
                ALUSrc_o = 1'b0;
                RegDst_o = 1'b0;
                Branch_o = 2'b01;
