            end
            6'b100011: begin // LW
                RegWrite_o = 1'b1;
                ALU_op_o = 3'b000;
                ALUSrc_o = 1'b1;
                RegDst_o = 1'b0;
                Branch_o = 2'b00;
                SignExtend_o = 1'b1;
                MemRead_o = 1'b1;
                MemWrite_o = 1'b0;
