module mux2 #(
    parameter WIDTH = 16
)(
    input [WIDTH-1:0] in0, in1,
    input select,
    output [WIDTH-1:0] out
);
    assign out = select ? in1 : in0;
endmodule

module mux4 #(
    parameter WIDTH = 16
)(
    input [WIDTH-1:0] in0, in1, in2, in3,
    input [1:0] select,
    output [WIDTH-1:0] out
);
    wire [WIDTH-1:0] mux1_out, mux2_out;

    mux2 #(WIDTH) mux1 (
        .in0(in0),
        .in1(in1),
        .select(select[0]),
        .out(mux1_out)
    );

    mux2 #(WIDTH) mux2 (
        .in0(in2),
        .in1(in3),
        .select(select[0]),
        .out(mux2_out)
    );

    mux2 #(WIDTH) mux3 (
        .in0(mux1_out),
        .in1(mux2_out),
        .select(select[1]),
        .out(out)
    );
endmodule

