module origen_028319 (
    input wire clk_lvds, clk_test, clkin, nrst,
    input wire coax_in, lvds_rx,
    input wire [7:0] mask1, mask2,
    input wire [7:0] deadticks, firingticks,
    input wire passthrough, resethist, vetopmtlast,
    input wire [7:0] cyclesToVeto,
    output reg [3:0] led,
    output reg [9:0] coax_out,
    output reg [7:0] histo [7:0],
    output reg [7:0] ipihist [63:0]
);

    reg [7:0] veto_counter;
    reg [7:0] ipi_counter;
    reg [2:0] pmt_state;
    reg inveto, collision, anyphot, cycletoggle;
    reg pmt1, pmt1_prev, pmt1test;
    reg [7:0] out1, out2;
    integer i;

    // Clock domain crossing
    reg lvds_rx_sync1, lvds_rx_sync2;
    always @(posedge clkin) begin
        lvds_rx_sync1 <= lvds_rx;
        lvds_rx_sync2 <= lvds_rx_sync1;
    end

    // Test mode
    always @(posedge clk_test) begin
        pmt1test <= ~pmt1test;
    end

    // Main logic
    always @(posedge clkin or negedge nrst) begin
        if (~nrst) begin
            pmt_state <= 3'b000;
            veto_counter <= 8'd0;
            ipi_counter <= 8'd0;
            inveto <= 1'b0;
            collision <= 1'b0;
            anyphot <= 1'b0;
            cycletoggle <= 1'b0;
            pmt1 <= 1'b0;
            pmt1_prev <= 1'b0;
            out1 <= 8'd0;
            out2 <= 8'd0;
            for (i = 0; i < 8; i = i + 1) histo[i] <= 8'd0;
            for (i = 0; i < 64; i = i + 1) ipihist[i] <= 8'd0;
        end else begin
            pmt1_prev <= pmt1;
            pmt1 <= passthrough ? lvds_rx_sync2 : (vetopmtlast ? (lvds_rx_sync2 & ~pmt1_prev) : lvds_rx_sync2);

            // Veto logic
            if (pmt1 && ~inveto) begin
                veto_counter <= cyclesToVeto;
                inveto <= 1'b1;
            end else if (veto_counter > 0) begin
                veto_counter <= veto_counter - 1;
            end else begin
                inveto <= 1'b0;
            end

            // Photon detection and masking
            if (pmt1 && ~inveto) begin
                out1 <= mask1;
                out2 <= mask2;
                anyphot <= 1'b1;

                // Update histograms
                for (i = 0; i < 8; i = i + 1) begin
                    if (mask1[i] || mask2[i]) histo[i] <= histo[i] + 1;
                end
                if (ipi_counter < 64) ipihist[ipi_counter] <= ipihist[ipi_counter] + 1;
                ipi_counter <= 0;
            end else begin
                out1 <= 8'd0;
                out2 <= 8'd0;
                anyphot <= 1'b0;
                if (ipi_counter < 8'd255) ipi_counter <= ipi_counter + 1;
            end

            // Collision detection
            collision <= (out1 != 8'd0) && (out2 != 8'd0);

            // Reset histograms
            if (resethist) begin
                for (i = 0; i < 8; i = i + 1) histo[i] <= 8'd0;
                for (i = 0; i < 64; i = i + 1) ipihist[i] <= 8'd0;
            end

            // Cycle toggle
            cycletoggle <= ~cycletoggle;
        end
    end

    // Output assignments
    always @(posedge clkin) begin
        led[0] <= pmt1;
        led[1] <= |out1;
        led[2] <= |out2;
        led[3] <= pmt1test;

        coax_out[0] <= pmt1;
        coax_out[1] <= lvds_rx_sync2;
        coax_out[2] <= |out1;
        coax_out[3] <= |out2;
        coax_out[4] <= pmt1test;
        coax_out[5] <= coax_in;
        coax_out[6] <= inveto;
        coax_out[7] <= collision;
        coax_out[8] <= anyphot;
        coax_out[9] <= cycletoggle;
    end

endmodule

