module autovcoder_002980 (
                            input             adc_clk,
                            input             rst,
    (* MARK_DEBUG="true" *) input      [11:0] adc_data,
    (* MARK_DEBUG="true" *) output reg        adc_buf_wr,
    (* MARK_DEBUG="true" *) output     [15:0] adc_buf_data,

    input      [31:0] sample_len,
    input             ad_sample_req,
    output reg        ad_sample_ack,

    input      write_req_ack,
    output reg write_req
);

  //`define TRIGGER

  localparam S_IDLE = 0;
  localparam S_REQ = 1;
  localparam S_ACK_WAIT = 2;
  localparam S_SAMPLE = 3;
  localparam S_WAIT = 4;

  reg signed [11:0] adc_data_signed;

  reg signed [15:0] adc_data_wide;
  reg signed [15:0] adc_data_wide_d0;
  (* MARK_DEBUG="true" *)reg        [31:0] sample_cnt;
  reg        [31:0] wait_cnt;


  reg               ad_sample_req_d0;
  reg               ad_sample_req_d1;
  reg               ad_sample_req_d2;

  reg        [ 2:0] state;

  assign adc_buf_data = adc_data_wide_d0;


  //תз
  always @(posedge adc_clk or posedge rst) begin
    if (rst == 1'b1) adc_data_signed <= 12'd0;
    else adc_data_signed <= adc_data - 2048;
  end


  //ת16λ뷽ʽ
  always @(posedge adc_clk or posedge rst) begin
    if (rst == 1'b1) adc_data_wide <= 16'd0;
    else adc_data_wide <= {{4{adc_data_signed[11]}}, adc_data_signed[11:0]};
  end

  always @(posedge adc_clk or posedge rst) begin
    if (rst == 1'b1) adc_data_wide_d0 <= 16'd0;
    else adc_data_wide_d0 <= adc_data_wide;
  end


  always @(posedge adc_clk or posedge rst) begin
    if (rst) begin
      ad_sample_req_d0 <= 1'b0;
      ad_sample_req_d1 <= 1'b0;
      ad_sample_req_d2 <= 1'b0;
    end else begin
      ad_sample_req_d0 <= ad_sample_req;
      ad_sample_req_d1 <= ad_sample_req_d0;
      ad_sample_req_d2 <= ad_sample_req_d1;
    end
  end

  always @(posedge adc_clk or posedge rst) begin
    if (rst == 1'b1) begin
      state <= S_IDLE;
      wait_cnt <= 32'd0;
      sample_cnt <= 32'd0;
      adc_buf_wr <= 1'b0;
      ad_sample_ack <= 1'b0;
    end else
      case (state)
        S_IDLE: begin
          if (ad_sample_req_d2)//wait_cnt == 32'd125000)
              begin
            write_req <= 1'b1;
            state <= S_REQ;
            wait_cnt <= 32'd0;
          end else begin
            state <= S_IDLE;
            wait_cnt <= wait_cnt + 1'b1;
          end
        end
        S_REQ: begin
          if (write_req_ack) begin
            write_req <= 1'b0;
            state <= S_ACK_WAIT;
          end else state <= S_REQ;
        end
        S_ACK_WAIT: begin
          if (wait_cnt == 32'd40) begin
            state <= S_SAMPLE;
            wait_cnt <= 32'd0;
          end else begin
            wait_cnt <= wait_cnt + 1'b1;
            state <= S_ACK_WAIT;
          end
        end
        S_SAMPLE: begin

          ad_sample_ack <= 1'b1;
          if (sample_cnt == sample_len) begin
            sample_cnt <= 11'd0;
            adc_buf_wr <= 1'b0;
            state <= S_WAIT;
          end else begin
            sample_cnt <= sample_cnt + 11'd1;
            adc_buf_wr <= 1'b1;
          end

        end
        S_WAIT: begin
          ad_sample_ack <= 1'b0;
          state <= S_IDLE;
        end
        default: state <= S_IDLE;
      endcase
  end

endmodule

