reg [1:0] loop_loop_state;
wire loop_loop_restarted;
wire loop_loop_waiting;
wire [24:0] conc2_2;
wire [24:0] conc2_3;
reg [24:0] r_4;
reg [24:0] divider_5;
wire zerop_6;
wire [4:0] conc2_7;
wire [5:0] conc2_8;
wire [6:0] conc2_9;
wire [7:0] conc2_10;
wire [8:0] conc2_11;
wire [9:0] conc2_12;
wire [10:0] conc2_13;
wire [11:0] conc2_14;
wire [12:0] conc2_15;
wire [13:0] conc2_16;
wire [14:0] conc2_17;
wire [15:0] conc2_18;
wire [16:0] conc2_19;
wire [17:0] conc2_20;
wire [18:0] conc2_21;
wire [19:0] conc2_22;
wire [20:0] conc2_23;
wire [21:0] conc2_24;
wire [22:0] conc2_25;
wire [23:0] conc2_26;
wire [24:0] conc2_27;
wire lt_28;
wire if_test_29;
wire [3:0] branch_t_30;
wire if_test_31;
wire [24:0] shr_32;
wire [24:0] minus_33;
wire [24:0] shr_34;
reg [3:0] loop_loop_result_1;
wire loop_loop_result_1_ready;

assign loop_loop_restarted = (st_loop_restarted == loop_loop_state);
assign loop_loop_waiting = (st_loop_waiting == loop_loop_state);
assign conc2_2 = { 3'd0 , dividend };
assign conc2_3 = { orgdiv , 21'd0 };
assign zerop_6 = ~|divider_5;
assign conc2_7 = { 1'd0 , orgdiv };
assign conc2_8 = { 1'd0 , conc2_7 };
assign conc2_9 = { 1'd0 , conc2_8 };
assign conc2_10 = { 1'd0 , conc2_9 };
assign conc2_11 = { 1'd0 , conc2_10 };
assign conc2_12 = { 1'd0 , conc2_11 };
assign conc2_13 = { 1'd0 , conc2_12 };
assign conc2_14 = { 1'd0 , conc2_13 };
assign conc2_15 = { 1'd0 , conc2_14 };
assign conc2_16 = { 1'd0 , conc2_15 };
assign conc2_17 = { 1'd0 , conc2_16 };
assign conc2_18 = { 1'd0 , conc2_17 };
assign conc2_19 = { 1'd0 , conc2_18 };
assign conc2_20 = { 1'd0 , conc2_19 };
assign conc2_21 = { 1'd0 , conc2_20 };
assign conc2_22 = { 1'd0 , conc2_21 };
assign conc2_23 = { 1'd0 , conc2_22 };
assign conc2_24 = { 1'd0 , conc2_23 };
assign conc2_25 = { 1'd0 , conc2_24 };
assign conc2_26 = { 1'd0 , conc2_25 };
assign conc2_27 = { 1'd0 , conc2_26 };
assign lt_28 = (r_4 < conc2_27);
assign if_test_29 = (zerop_6 || lt_28);
assign branch_t_30 = (r_4[3:0]);
assign if_test_31 = (divider_5 > r_4);
assign shr_32 = (divider_5 >> 1'd1);
assign minus_33 = (r_4 - divider_5);
assign shr_34 = (divider_5 >> 1'd1);
assign loop_loop_result_1_ready = (loop_loop_state == st_loop_ready);

// Main always block
always @(posedge clk) begin
    if (start) begin
        loop_loop_state <= st_loop_inits;
    end else begin
        case (loop_loop_state)
            st_loop_ready: begin
                // Do nothing
            end

            st_loop_inits: begin
                loop_loop_state <= st_loop_restarted;
                r_4 <= conc2_2;
                divider_5 <= conc2_3;
            end

            st_loop_restarted: begin
                loop_loop_state <= st_loop_waiting;
            end

            st_loop_waiting: begin
                if (if_test_29) begin
                    loop_loop_result_1 <= branch_t_30;
                    loop_loop_state <= st_loop_ready;
                end else if (if_test_31) begin
                    loop_loop_state <= st_loop_restarted;
                    r_4 <= r_4;
                    divider_5 <= shr_32;
                end else begin
                    loop_loop_state <= st_loop_restarted;
                    r_4 <= minus_33;
                    divider_5 <= shr_34;
                end
            end
        endcase
    end
end

// Assignments for the outputs
assign result = loop_loop_result_1;
assign result_ready = loop_loop_result_1_ready & (~start);

