module autovcoder_060779 (
    input clk8M,
    input reset,

    input   [7:0] sndno,
    input    sndstart,

    output [15:0] sndout,

    input    ROMCL,  // Downloaded ROM image
    input   [24:0] ROMAD,
    input   [7:0] ROMDT,
    input    ROMEN
);

  //----------------------------------
  //  ClockGen
  //----------------------------------
  wire clk4M, clk2M;
  SndClkGen clkgen (
      clk8M,
      clk4M,
      clk2M
  );

  wire cpuclkx2 = clk8M;
  wire cpu_clk = clk4M;


  //----------------------------------
  //  Z80 (1.5625MHz)
  //----------------------------------
  wire [15:0] cpu_ad;
  wire [7:0] cpu_di, cpu_do;
  wire cpu_mreq, cpu_iorq, cpu_rd, cpu_wr;
  wire cpu_irq, cpu_nmi;
  wire cpu_irqa, cpu_nmia;

  wire cpu_mw, cpu_cs_rom, cpu_cs_ram, cpu_wr_ram, cpu_cs_psg0, cpu_cs_psg1, cpu_cs_com;
  SndADec adec (
      cpu_mreq,
      cpu_wr,
      cpu_mw,
      cpu_ad,
      cpu_cs_rom,
      cpu_cs_ram,
      cpu_wr_ram,
      cpu_cs_psg0,
      cpu_cs_psg1,
      cpu_cs_com
  );

  Z80IP cpu (
      .clk(cpu_clk),
      .reset(reset),
      .adr(cpu_ad),
      .data_in(cpu_di),
      .data_out(cpu_do),
      .intreq(cpu_irq),
      .intack(cpu_irqa),
      .nmireq(cpu_nmi),
      .nmiack(cpu_nmia),
      .mx(cpu_mreq),
      .ix(cpu_iorq),
      .rd(cpu_rd),
      .wr(cpu_wr)
  );

  wire [7:0] rom_dt;  // ROM
  wire [7:0] ram_do;  // RAM
  wire [7:0] comlatch;  // Sound Command Latch

  DLROM #(13, 8) subir (
      cpuclkx2,
      cpu_ad[12:0],
      rom_dt,
      ROMCL,
      ROMAD,
      ROMDT,
      ROMEN & (ROMAD[16:13] == 4'b1_110)
  );  // $1C000-$1DFFF
  SRAM_2048 wram (
      cpuclkx2,
      cpu_ad[10:0],
      ram_do,
      cpu_wr_ram,
      cpu_do
  );

  dataselector3 scpudisel (
      cpu_di,
      cpu_cs_rom,
      rom_dt,
      cpu_cs_ram,
      ram_do,
      cpu_cs_com,
      comlatch,
      8'hFF
  );

  assign rom_ad = cpu_ad[12:0];

  SndPlayReq sndreq (
      clk4M,
      reset,
      sndno,
      sndstart,
      cpu_irq,
      cpu_irqa,
      cpu_nmi,
      cpu_nmia,
      comlatch
  );


  //----------------------------------
  //  PSGs
  //----------------------------------
  wire [7:0] psg0out, psg1out;

  SN76496 psg0 (
      clk2M,
      cpu_clk,
      reset,
      cpu_cs_psg0,
      cpu_mw,
      cpu_do,
      4'b1111,
      psg0out
  );

  SN76496 psg1 (
      clk4M,
      cpu_clk,
      reset,
      cpu_cs_psg1,
      cpu_mw,
      cpu_do,
      4'b1111,
      psg1out
  );

  wire [8:0] psgout = psg0out + psg1out;
  assign sndout = {psgout, 6'h0};

endmodule

