module autovcoder_062894 (
    input  [15:0] x,
    y,  // x and y (temporary)
    input         sub,     // 0 for add and 1 for subtract
    output [15:0] result,  // temporary output
    output        cout
);

  wire [15:0] c;  // carry-in/carry-out for adder
  wire [15:0] B;  // the XOR output for y
  wire [15:0] s;  // sum of x and y

  assign result = s;
  assign cout   = c[15];


  // XOR logic outputs
  xor (B[0], y[0], sub);
  xor (B[1], y[1], sub);
  xor (B[2], y[2], sub);
  xor (B[3], y[3], sub);
  xor (B[4], y[4], sub);
  xor (B[5], y[5], sub);
  xor (B[6], y[6], sub);
  xor (B[7], y[7], sub);
  xor (B[8], y[8], sub);
  xor (B[9], y[9], sub);
  xor (B[10], y[10], sub);
  xor (B[11], y[11], sub);
  xor (B[12], y[12], sub);
  xor (B[13], y[13], sub);
  xor (B[14], y[14], sub);
  xor (B[15], y[15], sub);

  // sends each bit to the full adder
  fullAdd a0 (
      x[0],
      B[0],
      sub,
      s[0],
      c[0]
  );
  fullAdd a1 (
      x[1],
      B[1],
