module autovcoder_074393 (  //	Host Side
    iCLK,
    iRST_N,
    d0x0,
    d0x1,
    d0x2,
    d0x3,
    d0x4,
    d0x5,
    d1x0,
    d1x1,
    d1x2,
    d1x3,
    d1x4,
    d1x5,
    //	LCD Side
    LCD_DATA,
    LCD_RW,
    LCD_EN,
    LCD_RS
);
  //	Host Side
  input iCLK, iRST_N;
  // Data test
  input [7:0] d0x0, d0x1, d0x2, d0x3, d0x4, d0x5, d1x0, d1x1, d1x2, d1x3, d1x4, d1x5;
  //	LCD Side
  output [7:0] LCD_DATA;
  output LCD_RW, LCD_EN, LCD_RS;
  //	Internal Wires/Registers
  reg [5:0] LUT_INDEX;
  reg [8:0] LUT_DATA;
  reg [5:0] mLCD_ST;
  reg [17:0] mDLY;
  reg mLCD_Start;
  reg [7:0] mLCD_DATA;
  reg mLCD_RS;
  wire mLCD_Done;

  parameter LCD_INTIAL = 0;
  parameter LCD_RESTART = 4;
  parameter LCD_LINE1 = 5;
  parameter LCD_CH_LINE = LCD_LINE1 + 16;
  parameter LCD_LINE2 = LCD_LINE1 + 16 + 1;
  parameter LUT_SIZE = LCD_LINE2 + 16 - 1;

  always @(posedge iCLK or negedge iRST_N) begin
    if (!iRST_N) begin
      LUT_INDEX <= 0;
      mLCD_ST <= 0;
      mDLY <= 0;
      mLCD_Start <= 0;
      mLCD_DATA <= 0;
      mLCD_RS <= 0;
    end else begin
      begin
        case (mLCD_ST)
          0: begin
            mLCD_DATA <= LUT_DATA[7:0];
            mLCD_RS <= LUT_DATA[8];
            mLCD_Start <= 1;
            mLCD_ST <= 1;
          end
          1: begin
            if (mLCD_Done) begin
              mLCD_Start <= 0;
              mLCD_ST <= 2;
            end
          end
          2: begin
            if (mDLY < 18'h3FFFE) mDLY <= mDLY + 1;
            else begin
              mDLY <= 0;
              mLCD_ST <= 3;
            end
          end
          3: begin
            if (LUT_INDEX < LUT_SIZE) LUT_INDEX <= LUT_INDEX + 1;
            else LUT_INDEX <= LCD_RESTART;
            mLCD_ST <= 0;
          end
        endcase
      end
    end
  end

  function [8:0] hex2char;
    input [3:0] h;
    hex2char = (h > 9 ? 9'h137 : 9'h130) + h;
  endfunction

  always begin
    case (LUT_INDEX)
      //	Initial
      LCD_INTIAL + 0: LUT_DATA <= 9'h038;
      LCD_INTIAL + 1: LUT_DATA <= 9'h00C;
      LCD_INTIAL + 2: LUT_DATA <= 9'h001;
      LCD_INTIAL + 3: LUT_DATA <= 9'h006;
      LCD_INTIAL + 4: LUT_DATA <= 9'h080;
      //	Line 1	
      LCD_LINE1 + 0:  LUT_DATA <= hex2char(d0x0[7:4]);
      LCD_LINE1 + 1:  LUT_DATA <= hex2char(d0x0[3:0]);
      LCD_LINE1 + 2:  LUT_DATA <= 9'h120;
      LCD_LINE1 + 3:  LUT_DATA <= hex2char(d0x1[7:4]);
      LCD_LINE1 + 4:  LUT_DATA <= hex2char(d0x1[3:0]);
      LCD_LINE1 + 5:  LUT_DATA <= 9'h120;
      LCD_LINE1 + 6:  LUT_DATA <= hex2char(d0x2[7:4]);
      LCD_LINE1 + 7:  LUT_DATA <= hex2char(d0x2[3:0]);
      LCD_LINE1 + 8:  LUT_DATA <= 9'h120;
      LCD_LINE1 + 9:  LUT_DATA <= hex2char(d0x3[7:4]);
      LCD_LINE1 + 10: LUT_DATA <= hex2char(d0x3[3:0]);
      LCD_LINE1 + 11: LUT_DATA <= 9'h120;
      LCD_LINE1 + 12: LUT_DATA <= hex2char(d0x4[7:4]);
      LCD_LINE1 + 13: LUT_DATA <= hex2char(d0x4[3:0]);
      LCD_LINE1 + 14: LUT_DATA <= 9'h120;
      LCD_LINE1 + 15: LUT_DATA <= hex2char(d0x5[3:0]);
      //	Change Line               
      LCD_CH_LINE:    LUT_DATA <= 9'h0C0;
      //	Line 2                    
      LCD_LINE2 + 0:  LUT_DATA <= hex2char(d1x0[7:4]);
      LCD_LINE2 + 1:  LUT_DATA <= hex2char(d1x0[3:0]);
      LCD_LINE2 + 2:  LUT_DATA <= 9'h120;
      LCD_LINE2 + 3:  LUT_DATA <= hex2char(d1x1[7:4]);
      LCD_LINE2 + 4:  LUT_DATA <= hex2char(d1x1[3:0]);
      LCD_LINE2 + 5:  LUT_DATA <= 9'h120;
      LCD_LINE2 + 6:  LUT_DATA <= hex2char(d1x2[7:4]);
      LCD_LINE2 + 7:  LUT_DATA <= hex2char(d1x2[3:0]);
      LCD_LINE2 + 8:  LUT_DATA <= 9'h120;
      LCD_LINE2 + 9:  LUT_DATA <= hex2char(d1x3[7:4]);
      LCD_LINE2 + 10: LUT_DATA <= hex2char(d1x3[3:0]);
      LCD_LINE2 + 11: LUT_DATA <= 9'h120;
      LCD_LINE2 + 12: LUT_DATA <= hex2char(d1x4[7:4]);
      LCD_LINE2 + 13: LUT_DATA <= hex2char(d1x4[3:0]);
      LCD_LINE2 + 14: LUT_DATA <= 9'h120;
      LCD_LINE2 + 15: LUT_DATA <= hex2char(d1x5[3:0]);
      default:        LUT_DATA <= 9'h120;
    endcase
  end

  LCD_Controller u0 (  //	Host Side
      .iDATA(mLCD_DATA),
      .iRS(mLCD_RS),
      .iStart(mLCD_Start),
      .oDone(mLCD_Done),
      .iCLK(iCLK),
      .iRST_N(iRST_N),
      //	LCD Interface
      .LCD_DATA(LCD_DATA),
      .LCD_RW(LCD_RW),
      .LCD_EN(LCD_EN),
      .LCD_RS(LCD_RS)
  );

endmodule

files.conformal_rtl_autovcoder_074393.do:
// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.
// NOTE: Conformal uses // for comments. Do NOT use # (Conformal treats # as a command and aborts).

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

