module rtlpp_03536(
    input aclk,
    input aresetn,
    input [31:0] s_axi_awaddr,
    input [2:0] s_axi_awprot,
    input [0:0] s_axi_awvalid,
    output [0:0] s_axi_awready,
    input [31:0] s_axi_wdata,
    input [3:0] s_axi_wstrb,
    input [0:0] s_axi_wvalid,
    output [0:0] s_axi_wready,
    output [1:0] s_axi_bresp,
    output [0:0] s_axi_bvalid,
    input [0:0] s_axi_bready,
    input [31:0] s_axi_araddr,
    input [2:0] s_axi_arprot,
    input [0:0] s_axi_arvalid,
    output [0:0] s_axi_arready,
    output [31:0] s_axi_rdata,
    output [1:0] s_axi_rresp,
    output [0:0] s_axi_rvalid,
    input [0:0] s_axi_rready,
    output [63:0] m_axi_awaddr,
    output [5:0] m_axi_awprot,
    output [1:0] m_axi_awvalid,
    input [1:0] m_axi_awready,
    output [63:0] m_axi_wdata,
    output [7:0] m_axi_wstrb,
    output [1:0] m_axi_wvalid,
    input [1:0] m_axi_wready,
    input [3:0] m_axi_bresp,
    input [1:0] m_axi_bvalid,
    output [1:0] m_axi_bready,
    output [63:0] m_axi_araddr,
    output [5:0] m_axi_arprot,
    output [1:0] m_axi_arvalid,
    input [1:0] m_axi_arready,
    input [63:0] m_axi_rdata,
    input [3:0] m_axi_rresp,
    input [1:0] m_axi_rvalid,
    output [1:0] m_axi_rready
);
    // Internal registers and wires declaration
    reg [0:0] s_axi_awready;
    reg [0:0] s_axi_wready;
    reg [1:0] s_axi_bresp;
    reg [0:0] s_axi_bvalid;
    reg [0:0] s_axi_arready;
    reg [31:0] s_axi_rdata;
    reg [1:0] s_axi_rresp;
    reg [0:0] s_axi_rvalid;

    reg [63:0] m_axi_awaddr;
    reg [5:0] m_axi_awprot;
    reg [1:0] m_axi_awvalid;
    reg [63:0] m_axi_wdata;
    reg [7:0] m_axi_wstrb;
    reg [1:0] m_axi_wvalid;
    reg [1:0] m_axi_bready;
    reg [63:0] m_axi_araddr;
    reg [5:0] m_axi_arprot;
    reg [1:0] m_axi_arvalid;
    reg [1:0] m_axi_rready;

    // AXI write address channel
    always @(posedge aclk) begin
        if (~aresetn) begin
            s_axi_awready <= 1'b0;
        end else begin
            s_axi_awready <= s_axi_awvalid & ~s_axi_awready;
        end
    end

    // AXI write data channel
    always @(posedge aclk) begin
        if (~aresetn) begin
            s_axi_wready <= 1'b0;
        end else begin
            s_axi_wready <= s_axi_wvalid & ~s_axi_wready;
        end
    end

    // AXI write response channel
    always @(posedge aclk) begin
        if (~aresetn) begin
            s_axi_bvalid <= 1'b0;
            s_axi_bresp <= 2'b00;
        end else if (s_axi_bready & s_axi_bvalid) begin
            s_axi_bvalid <= 1'b0;
        end else if (s_axi_wready & s_axi_wvalid & s_axi_awready & s_axi_awvalid) begin
            s_axi_bvalid <= 1'b1;
            s_axi_bresp <= 2'b00; // OKAY response for simplified example
        end
    end

    // AXI read address channel
    always @(posedge aclk) begin
        if (~aresetn) begin
            s_axi_arready <= 1'b0;
        end else begin
            s_axi_arready <= s_axi_arvalid & ~s_axi_arready;
        end
    end

    // AXI read data channel
    always @(posedge aclk) begin
        if (~aresetn) begin
            s_axi_rvalid <= 1'b0;
            s_axi_rdata <= 32'h00000000;
            s_axi_rresp <= 2'b00;
        end else if (s_axi_rready & s_axi_rvalid) begin
            s_axi_rvalid <= 1'b0;
        end else if (s_axi_arready & s_axi_arvalid) begin
            s_axi_rvalid <= 1'b1;
            s_axi_rdata <= 32'hDEADBEEF; // Example fixed data
            s_axi_rresp <= 2'b00; // OKAY response for simplified example
        end
    end

    // Master AXI interface examples for simplification

    always @(posedge aclk) begin
        if (~aresetn) begin
            m_axi_awvalid <= 2'b00;
            m_axi_awaddr <= 64'h0000000000000000;
            m_axi_awprot <= 6'b000000;
        end else begin
            m_axi_awvalid <= {s_axi_awvalid, s_axi_awvalid};
            m_axi_awaddr <= {s_axi_awaddr, s_axi_awaddr};
            m_axi_awprot <= {s_axi_awprot, s_axi_awprot};
        end
    end

    always @(posedge aclk) begin
        if (~aresetn) begin
            m_axi_wvalid <= 2'b00;
            m_axi_wdata <= 64'h0000000000000000;
            m_axi_wstrb <= 8'b00000000;
        end else begin
            m_axi_wvalid <= {s_axi_wvalid, s_axi_wvalid};
            m_axi_wdata <= {s_axi_wdata, s_axi_wdata};
            m_axi_wstrb <= {s_axi_wstrb, s_axi_wstrb};
        end
    end

    always @(posedge aclk) begin
        if (~aresetn) begin
            m_axi_bready <= 2'b00;
        end else begin
            m_axi_bready <= {s_axi_bready, s_axi_bready};
        end
    end

    always @(posedge aclk) begin
        if (~aresetn) begin
            m_axi_arvalid <= 2'b00;
            m_axi_araddr <= 64'h0000000000000000;
            m_axi_arprot <= 6'b000000;
        end else begin
            m_axi_arvalid <= {s_axi_arvalid, s_axi_arvalid};
            m_axi_araddr <= {s_axi_araddr, s_axi_araddr};
            m_axi_arprot <= {s_axi_arprot, s_axi_arprot};
        end
    end

    always @(posedge aclk) begin
        if (~aresetn) begin
