module autovcoder_068784 (
    clk,
    enable,
    reset,
    soundwave,
    enable_draw,
    X_out,
    Y_out
);

  input clk, enable, reset, soundwave;
  output reg enable_draw;
  output [7:0] X_out;
  output [6:0] Y_out;
  reg  [7:0] X_;
  reg  [6:0] Y_;
  wire [6:0] y_increase = 7'd4;
  reg  [6:0] y_shift;

  always @(posedge clk) begin
    if (reset) begin
      X_ <= 8'd0;
      Y_ <= 7'd6;
      enable_draw <= 1'b0;
      y_shift <= 7'd0;
    end

    if (enable) begin
      X_ <= X_ + 1;

      if (X_ >= 8'd124) begin

        if (Y_ >= 7'd110) begin
          X_ <= 8'd155;
          Y_ <= 7'd112;
          enable_draw <= 1'b0;
        end else begin
          enable_draw <= 1'b1;
          X_ <= 8'd0;
          Y_ <= Y_ + y_increase;
        end
      end else enable_draw <= 1'b1;

      if (soundwave) y_shift <= 7'd0;
      else y_shift <= 7'd2;
    end else enable_draw <= 1'b0;
  end

  assign X_out = X_;
  assign Y_out = Y_ - y_shift;


endmodule

files.autovcoder_130206.v:
module autovcoder_130206 (  
    input clk,  
    input rst,  
    input [63:0] plaintext,  
    input [63:0] key,  
    output reg [63:0] ciphertext  
);  

    reg [63:0] data;  
    reg [63:0] subkey;  
    reg [47:0] round_keys [15:0];  

    // Initial permutation (simplified)
    wire [63:0] ip;  
    assign ip = {plaintext[63:56], plaintext[55:48], plaintext[47:40], plaintext[39:32],  
                 plaintext[31:24], plaintext[23:16], plaintext[15:8], plaintext[7:0]};  

    // Key schedule (simplified)
    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            subkey <= key;  
        end else begin  
            // Generate round keys (simplified)
            round_keys[0] <= subkey[63:16];  
            round_keys[1] <= subkey[15:0];  
            // ... (subkey generation for rounds 2-15)  
            round_keys[15] <= subkey[63:16];  
        end  
    end  

    // DES processing (simplified)
    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            data <= 64'b0;  
            ciphertext <= 64'b0;  
        end else begin  
            data <= ip;  
            // Apply 16 rounds (simplified)  
            for (integer i = 0; i < 16; i = i + 1) begin  
                // Simplified round function  
                data <= data ^ round_keys[i];  
            end  
            // Final permutation (simplified)
            ciphertext <= {data[63:56], data[55:48], data[47:40], data[39:32],  
                           data[31:24], data[23:16], data[15:8], data[7:0]};  
        end  
    end  
endmodule

files.autovcoder_112560.v:
module autovcoder_112560 (
    // Inputs
      input       clk_i
    , input       rst_i
    , input       hold_i
    , input [3:0] request_i

    // Outputs
    , output [3:0] grant_o
);


  //-----------------------------------------------------------------
  // Registers / Wires
  //-----------------------------------------------------------------
  wire [3:0] req_ffs_masked_w;
  wire [3:0] req_ffs_unmasked_w;
  wire [3:0] req_ffs_w;

  reg  [3:0] mask_next_q;
  reg  [3:0] grant_last_q;
  wire [3:0] grant_new_w;

  //-----------------------------------------------------------------
  // ffs: Find first set
  //-----------------------------------------------------------------
  function [3:0] ffs;
    input [3:0] request;
    begin
      ffs[0] = request[0];
      ffs[1] = ffs[0] | request[1];
      ffs[2] = ffs[1] | request[2];
      ffs[3] = ffs[2] | request[3];
    end
  endfunction

  assign req_ffs_masked_w = ffs(request_i & mask_next_q);
  assign req_ffs_unmasked_w = ffs(request_i);

  assign req_ffs_w = (|req_ffs_masked_w) ? req_ffs_masked_w : req_ffs_unmasked_w;

  always @(posedge clk_i or posedge rst_i)
    if (rst_i == 1'b1) begin
      mask_next_q  <= {4{1'b1}};
      grant_last_q <= 4'b0;
    end else begin
      if (~hold_i) mask_next_q <= {req_ffs_w[2:0], 1'b0};

      grant_last_q <= grant_o;
    end

  assign grant_new_w = req_ffs_w ^ {req_ffs_w[2:0], 1'b0};
  assign grant_o = hold_i ? grant_last_q : grant_new_w;


endmodule

files.autovcoder_140308.v:
module autovcoder_140308 (
    input wire clk,
    input wire reset,
    input wire push,
    input wire pop,
    input wire [3:0] data_in,
    output reg [3:0] stack_out,
    output reg [2:0] depth,
    output reg overflow,
    output reg underflow
);
    reg [3:0] stack [7:0]; // 8 depth stack
    reg [2:0] top; // points to the current top of the stack

    initial begin
        top = 3'b000;
        overflow = 0;
        underflow = 0;
        depth = 3'b000;
    end

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            top <= 3'b000;
            depth <= 3'b000;
            overflow <= 0;
            underflow <= 0;
        end else begin
            if (push && (top < 3'b111)) begin // Check for overflow
                stack[top] <= data_in;
                top <= top + 1;
                depth <= depth + 1;
                overflow <= 0;
            end else if (push) begin
                overflow <= 1; // Overflow condition
            end

            if (pop && (top > 3'b000)) begin // Check for underflow
                top <= top - 1;
                stack_out <= stack[top - 1];
                depth <= depth - 1;
                underflow <= 0;
            end else if (pop) begin
                underflow <= 1; // Underflow condition
            end
        end
    end
endmodule

