module autovcoder_121346 (
    clk,
    data,
    ce,
    a,
    q
);

  parameter DATA_WIDTH = 32'd1;
  parameter ADDR_WIDTH = 32'd4;
  parameter DEPTH = 5'd9;

  input clk;
  input [DATA_WIDTH-1:0] data;
  input ce;
  input [ADDR_WIDTH-1:0] a;
  output reg [DATA_WIDTH-1:0] q;

  reg [DATA_WIDTH-1:0] sr_0, sr_1, sr_2, sr_3, sr_4, sr_5, sr_6, sr_7, sr_8;
  integer i;

  always @(posedge clk) begin
    if (ce) begin
      sr_0 <= data;
      sr_1 <= sr_0;
      sr_2 <= sr_1;
      sr_3 <= sr_2;
      sr_4 <= sr_3;
      sr_5 <= sr_4;
      sr_6 <= sr_5;
      sr_7 <= sr_6;
      sr_8 <= sr_7;


    end
  end

  always @(sr_0, sr_1, sr_2, sr_3, sr_4, sr_5, sr_6, sr_7, sr_8, a) begin
    case (a)
      4'd0: q = sr_0;
      4'd1: q = sr_1;
      4'd2: q = sr_2;
      4'd3: q = sr_3;
      4'd4: q = sr_4;
      4'd5: q = sr_5;
      4'd6: q = sr_6;
      4'd7: q = sr_7;
      4'd8: q = sr_8;
      default: q = sr_8;
    endcase
  end

endmodule

