module origen_209317(
    input clk,
    input reset,
    input start_receiving,
    input ps2_clk,
    input ps2_dat,
    output reg [7:0] command,
    output reg received
);

reg [2:0] clk_div;
reg process_cmd;
reg [3:0] counter;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        clk_div <= 3'h7;
        counter <= 4'b0;
        command <= 8'b0;
        process_cmd <= 1'b0;
        received <= 1'b0;
    end
    else begin
        if (start_receiving) begin
            process_cmd <= 1'b1;
        end
        if (process_cmd) begin
            if (clk_div == 3'h0) begin
                clk_div <= 3'h7;
                if (counter == 4'b1011) begin
                    process_cmd <= 1'b0;
                    received <= 1'b1;
                end
                else begin
                    command <= {command[6:0], ps2_dat};
                    counter <= counter + 1'b1;
                end
            end
            else begin
                clk_div <= clk_div - 1'b1;
            end
        end
        else begin
            received <= 1'b0;
        end
    end
end

assign ps2_clk = process_cmd ? 1'b0 : 1'bz;
assign ps2_dat = process_cmd ? 1'b0 : 1'bz;

endmodule

files.origen_200184.v:
module origen_200184(
    input clk,
    input reset,
    input ain,
    output reg [3:0] count,
    output reg yout,
    output reg [1:0] state,
    output reg [1:0] nextstate
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        state <= 2'b00;
        count <= 4'b0000;
    end
    else begin
        state <= nextstate;
        count <= count + ain;
    end
end

always @(*) begin
    case (state)
        2'b00: begin // S0
            yout = ~ain;
            if (ain) nextstate = 2'b01;
            else nextstate = 2'b00;
        end
        2'b01: begin // S1
            yout = 1'b0;
            if (ain) nextstate = 2'b10;
            else nextstate = 2'b01;
        end
        2'b10: begin // S2
            yout = 1'b0;
            if (ain) nextstate = 2'b11;
            else nextstate = 2'b10;
        end
        2'b11: begin // S3
            yout = ain;
            if (ain) nextstate = 2'b01;
            else nextstate = 2'b11;
        end
        default: begin
            yout = 1'b0;
            nextstate = 2'b00;
        end
    endcase
end

endmodule

