    always @(posedge clk) begin
        if (reset) begin
            mux_1_1_reg <= {din2_WIDTH{1'b0}};
        end else if (ce) begin
            mux_1_1_reg <= din2;
        end
    end

    assign mux_2_0 = (sel1 == 1'b0) ? mux_1_0_reg : mux_1_1_reg;

    assign dout = mux_2_0;

