module origen_004227 (
    input wire clk,
    input wire rst,
    input wire dispatch_en_i,
    input wire retire_en_i,
    input wire [5:0] retire_preg_i,
    input wire recover_en_i,
    input wire [4:0] recover_head_i,
    output reg free_preg_vld_o,
    output reg [5:0] free_preg_o,
    output reg [4:0] free_preg_cur_head_o
);

    reg [5:0] FL [31:0];
    reg [4:0] head, tail;
    reg [5:0] count;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            head <= 5'd0;
            tail <= 5'd0;
            count <= 6'd32;
            free_preg_vld_o <= 1'b1;
            free_preg_o <= 6'd32;
            free_preg_cur_head_o <= 5'd0;
            for (int i = 0; i < 32; i++) begin
                FL[i] <= i + 32;
            end
        end else begin
            if (recover_en_i) begin
                head <= recover_head_i;
                count <= 6'd32 - (recover_head_i - tail);
            end else begin
                if (dispatch_en_i && count > 0) begin
                    head <= head + 1;
                    count <= count - 1;
                end
                if (retire_en_i && count < 32) begin
                    FL[tail] <= retire_preg_i;
                    tail <= tail + 1;
                    count <= count + 1;
                end
            end

            free_preg_vld_o <= (count > 0);
            free_preg_o <= (dispatch_en_i && count > 0) ? FL[head] :
                           (retire_en_i && count < 32) ? retire_preg_i : free_preg_o;
            free_preg_cur_head_o <= head;
        end
    end

endmodule

files.origen_133855.v:
module origen_133855(
    input wire clk,
    input wire rst_n,
    input wire data_in,
    input wire [7:0] and_input,
    output wire [7:0] final_output
);

    wire edge_detected;
    wire [7:0] shift_reg_out;
    wire [7:0] and_out;

    // Modified Dual-Edge Triggered Flip-Flop
    reg q1, q2;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            q1 <= 1'b0;
        else
            q1 <= data_in;
    end

    always @(negedge clk or negedge rst_n) begin
        if (!rst_n)
            q2 <= 1'b0;
        else
            q2 <= data_in;
    end

    wire deff_out = (clk) ? q2 : q1;

    // Rising Edge Detector
    reg clk_prev;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            clk_prev <= 1'b0;
        else
            clk_prev <= clk;
    end

    assign edge_detected = clk & ~clk_prev;

    // 8-bit Shift Register
    reg [7:0] shift_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            shift_reg <= 8'b0;
        else if (edge_detected)
            shift_reg <= {shift_reg[6:0], deff_out};
    end

    assign shift_reg_out = shift_reg;

    // Bitwise AND operation
    assign and_out = shift_reg_out & and_input;

    // XOR operation for final output
    assign final_output = and_out ^ {7'b0, edge_detected};

endmodule

