module origen_097815(
    input clk,
    input [15:0] SW,
    output CA, CB, CC, CD, CE, CF, CG, DP,
    output [7:0] AN
);

    reg [10:0] hcnt;
    reg [7:0] lpos;
    reg [31:0] cnt;
    reg [7:0] rseg;

    assign AN = ~lpos;

    always @(posedge clk) begin
        if (hcnt == 11'h7FF) begin
            hcnt <= 0;
            lpos <= {lpos[6:0], lpos[7]};
        end else begin
            hcnt <= hcnt + 1;
        end
    end

    always @(posedge clk) begin
        if (SW[0])
            cnt <= 0;
        else if (SW[1] && lpos[7])
            cnt <= cnt + {24'b0, SW[9:2]};
    end

    function [7:0] enc;
        input [1:0] val;
        case (val)
            2'b00: enc = 8'b11000000;
            2'b01: enc = 8'b11111001;
            2'b10: enc = 8'b10100100;
            2'b11: enc = 8'b10110000;
        endcase
    endfunction

    always @* begin
        case (lpos)
            8'b10000000: rseg = enc(cnt[1:0]);
            8'b01000000: rseg = enc(cnt[3:2]);
            8'b00100000: rseg = enc(cnt[5:4]);
            8'b00010000: rseg = enc(cnt[7:6]);
            8'b00001000: rseg = enc(cnt[9:8]);
            8'b00000100: rseg = enc(cnt[11:10]);
            8'b00000010: rseg = enc(cnt[13:12]);
            8'b00000001: rseg = enc(cnt[15:14]);
            default: rseg = 8'b11111111;
        endcase
    end

    assign {CA, CB, CC, CD, CE, CF, CG, DP} = rseg;

endmodule

files.origen_007269.v:
module origen_007269 (
    input wire clk,
    input wire rst,
    input wire tx_en,
    input wire [7:0] tx_data,
    input wire bpsclk,
    output wire tx_stop,
    output wire tx_out
);

    reg [3:0] i;
    reg rTX;
    reg isDone;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            i <= 4'd0;
            rTX <= 1'b1;
            isDone <= 1'b0;
        end else if (bpsclk) begin
            case (i)
                4'd0: begin
                    if (tx_en) begin
                        rTX <= 1'b0;  // Start bit
                        i <= i + 1'b1;
                        isDone <= 1'b0;
                    end
                end
                4'd1, 4'd2, 4'd3, 4'd4, 4'd5, 4'd6, 4'd7, 4'd8: begin
                    rTX <= tx_data[i-1];  // Data bits
                    i <= i + 1'b1;
                end
                4'd9, 4'd10: begin
                    rTX <= 1'b1;  // Stop bits
                    i <= i + 1'b1;
                end
                4'd11: begin
                    isDone <= 1'b1;  // Transmission complete
                    i <= i + 1'b1;
                end
                4'd12: begin
                    i <= 4'd0;  // Reset for next transmission
                    isDone <= 1'b0;
                end
                default: i <= 4'd0;
            endcase
        end
    end

    assign tx_out = rTX;
    assign tx_stop = isDone;

endmodule

