    end

    always @(*) begin
        case (digit)
            4'b0000: a_to_g = 7'b1000000;
            4'b0001: a_to_g = 7'b1111001;
            4'b0010: a_to_g = 7'b0100100;
            4'b0011: a_to_g = 7'b0110000;
