module origen_102303 (
    input logic clk,
    input logic resetN,
    input logic game_state,
    input logic [10:0][7:0] RGB_ball,
    input logic [7:0] RGB_stick,
    input logic [10:0] ball_request,
    input logic stick_request,
    input logic [7:0] RGB_backGround,
    input logic [7:0] RGB_strikes_units,
    input logic [7:0] RGB_strikes_tens,
    input logic strikes_units_request,
    input logic strikes_tens_request,
    output logic [7:0] redOut,
    output logic [7:0] greenOut,
    output logic [7:0] blueOut
);

    logic [7:0] tmpRGB;

    always_ff @(posedge clk or negedge resetN) begin
        if (!resetN) begin
            tmpRGB <= 8'b0;
        end else begin
            if (game_state) begin
                if (stick_request)
                    tmpRGB <= RGB_stick;
                else if (|ball_request) begin
                    tmpRGB <= RGB_backGround; // Default value
                    for (int i = 0; i < 11; i++) begin
                        if (ball_request[i]) begin
                            tmpRGB <= RGB_ball[i];
                            break;
                        end
                    end
                end
                else if (strikes_tens_request)
                    tmpRGB <= RGB_strikes_tens;
                else if (strikes_units_request)
                    tmpRGB <= RGB_strikes_units;
                else
                    tmpRGB <= RGB_backGround;
            end else begin
                tmpRGB <= RGB_backGround;
            end
        end
    end

    // Color expansion
    assign redOut   = {tmpRGB[7:5], tmpRGB[7:5], tmpRGB[7:6]};
    assign greenOut = {tmpRGB[4:2], tmpRGB[4:2], tmpRGB[4:3]};
    assign blueOut  = {tmpRGB[1:0], tmpRGB[1:0], tmpRGB[1:0], tmpRGB[1:0]};

endmodule

