module origen_034959(
    input [7:0] accin,
    input cin,
    input clk,
    input clear,
    output [7:0] accout,
    output cout
);

    wire [7:0] sum;
    wire carry;

    add8 adder (
        .a(accout),
        .b(accin),
        .cin(cin),
        .sum(sum),
        .cout(carry)
    );

    reg8 accumulator (
        .d(sum),
        .clk(clk),
        .clear(clear),
        .q(accout)
    );

    assign cout = carry;

endmodule

module add8(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);

    assign {cout, sum} = a + b + cin;

endmodule

module reg8(
    input [7:0] d,
    input clk,
    input clear,
    output reg [7:0] q
);

    always @(posedge clk or posedge clear) begin
        if (clear)
            q <= 8'b0;
        else
            q <= d;
    end

endmodule

files.origen_116763.v:
module origen_116763 #(parameter WIDTH = 8) (
    input wire reset_n,
    input wire clk,
    input wire enable,
    input wire [WIDTH-1:0] din,
    output reg [WIDTH-1:0] dout
);

always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        dout <= 0;
    end else if (enable) begin
        dout <= din;
    end
end

endmodule

module mult_shift_reg #(parameter WIDTH = 8) (
    input wire reset_n,
    input wire clk,
    input wire enable,
    input wire shift,
    input wire shift_in,
    input wire [WIDTH-1:0] din,
    output reg [WIDTH-1:0] dout
);

always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        dout <= 0;
    end else if (enable) begin
        dout <= din;
    end else if (shift) begin
        dout <= {shift_in, dout[WIDTH-1:1]};
    end
end

endmodule

module up_counter (
    input wire reset_n,
    input wire enable,
    input wire clk,
    output wire done
);

reg [7:0] cntInc;

always @(posedge clk) begin
    if (reset_n) begin
        cntInc <= 8'b0;
    end else if (enable) begin
        cntInc <= cntInc + 1'b1;
    end
end

assign done = (cntInc == 8'd32);

endmodule

