module origen_109165(
    input wire clk,
    input wire reset,
    input wire [11:0] irOutput,
    input wire pushBtnLeft,
    input wire pushBtnRight,
    input wire [11:0] switches,
    output reg [3:0] D_addr,
    output reg D_rd,
    output reg D_wr,
    output reg RF_we,
    output reg [2:0] RF_waddr,
    output reg isExternal,
    output reg AluSel,
    output reg [2:0] ra,
    output reg [2:0] rb
);

    // State encoding
    localparam S0 = 3'b000;
    localparam S1 = 3'b001;
    localparam S2a = 3'b010;
    localparam S2b = 3'b011;
    localparam S2c = 3'b100;
    localparam S2d = 3'b101;
    localparam S3 = 3'b110;

    reg [2:0] state, next_state;
    reg [2:0] opcode;

    // State register
    always @(posedge clk or posedge reset) begin
        if (reset)
            state <= S0;
        else
            state <= next_state;
    end

    // Next state logic
    always @(*) begin
        case (state)
            S0: next_state = S1;
            S1: begin
                case (opcode)
                    3'b000: next_state = S2a;
                    3'b001: next_state = S2b;
                    3'b010: next_state = S2c;
                    3'b011: next_state = S2d;
                    default: next_state = S3;
                endcase
            end
            S2a, S2b, S2c, S2d: next_state = S3;
            S3: next_state = S0;
            default: next_state = S0;
        endcase
    end

    // Output logic
    always @(*) begin
        // Default values
        D_addr = 4'b0000;
        D_rd = 1'b0;
        D_wr = 1'b0;
        RF_we = 1'b0;
        RF_waddr = 3'b000;
        isExternal = 1'b0;
        AluSel = 1'b0;
        ra = 3'b000;
        rb = 3'b000;

        case (state)
            S0: begin
                isExternal = pushBtnRight;
            end
            S1: begin
                opcode = irOutput[11:9];
                ra = irOutput[8:6];
                rb = irOutput[5:3];
                RF_waddr = irOutput[2:0];
            end
            S2a: begin
                D_addr = irOutput[3:0];
                D_rd = 1'b1;
                RF_we = 1'b1;
            end
            S2b: begin
                D_addr = irOutput[3:0];
                D_wr = 1'b1;
            end
            S2c: begin
                RF_we = 1'b1;
                AluSel = 1'b0;
            end
            S2d: begin
                RF_we = 1'b1;
                AluSel = 1'b1;
            end
            S3: begin
                // No specific outputs
            end
        endcase
    end

endmodule

files.origen_222975.v:
module origen_222975 (
    input sys_clk,
    input sys_rst,
    input [13:0] csr_a,
    input csr_we,
    input [31:0] csr_di,
    inout [3:0] mc_d,
    input mc_cmd,
    output mc_clk,
    output [31:0] csr_do
);

reg [3:0] mc_d_reg;
reg mc_clk_reg;
reg [31:0] csr_do_reg;

reg [6:0] state;
reg [31:0] cmd_reg;
reg [31:0] data_reg;
reg [31:0] csr_reg [0:63];

parameter IDLE = 7'b0000001;
parameter SEND_CMD = 7'b0000010;
parameter RECEIVE_RESP = 7'b0000100;
parameter SEND_DATA = 7'b0001000;
parameter RECEIVE_DATA = 7'b0010000;
parameter UPDATE_CSR = 7'b0100000;
parameter ERROR = 7'b1000000;

always @(posedge sys_clk or posedge sys_rst) begin
    if (sys_rst) begin
        state <= IDLE;
        mc_d_reg <= 4'b0;
        mc_clk_reg <= 1'b0;
        cmd_reg <= 32'b0;
        data_reg <= 32'b0;
        csr_do_reg <= 32'b0;
    end else begin
        case (state)
            IDLE: begin
                if (csr_we) begin
                    csr_reg[csr_a] <= csr_di;
                    state <= UPDATE_CSR;
                end else begin
                    state <= SEND_CMD;
                end
            end
            SEND_CMD: begin
                if (cmd_reg[31:24] == 8'haa) begin
                    mc_d_reg <= cmd_reg[7:4];
                    mc_clk_reg <= 1'b1;
                    cmd_reg <= {cmd_reg[23:0], 8'b0};
                    if (cmd_reg[31:24] == 8'b0) begin
                        state <= RECEIVE_RESP;
                    end
                end else begin
                    state <= ERROR;
                end
            end
            RECEIVE_RESP: begin
                mc_d_reg <= 4'b0;
                mc_clk_reg <= 1'b0;
                data_reg <= {data_reg[27:0], mc_d};
                if (data_reg[31:24] == 8'hbb) begin
                    state <= SEND_DATA;
                end else begin
                    state <= ERROR;
                end
            end
            SEND_DATA: begin
                mc_d_reg <= data_reg[7:4];
                mc_clk_reg <= 1'b1;
                data_reg <= {data_reg[27:0], 4'b0};
                if (data_reg[31:24] == 8'b0) begin
                    state <= RECEIVE_DATA;
                end
            end
            RECEIVE_DATA: begin
                mc_d_reg <= 4'b0;
                mc_clk_reg <= 1'b0;
                data_reg <= {data_reg[27:0], mc_d};
                if (data_reg[31:24] == 8'hcc) begin
                    state <= IDLE;
                end else begin
                    state <= ERROR;
                end
            end
            UPDATE_CSR: begin
                csr_do_reg <= csr_reg[csr_a];
                state <= IDLE;
            end
            ERROR: begin
                state <= IDLE;
            end
        endcase
    end
end

assign mc_d = (state == SEND_CMD || state == SEND_DATA) ? mc_d_reg : 4'bZ;
assign mc_clk = mc_clk_reg;
assign csr_do = csr_do_reg;

endmodule

files.autovcoder_010622.v:
module autovcoder_010622 (
    // global
    clk,
    rstn,
    // dat_i
    val_i,
    ai,
    bi,
    // dat_o
    val_o,
    ppo,
    so,
    eo
);

  //*** PARAMETER ****************************************************************
  parameter MUL_IN_WD = -1;
  localparam BOOTH2_TRA_WD = 3;
  localparam PRODCUT_OUT_WD = MUL_IN_WD + 1;
  localparam BOOTH2_TRA_NUM = MUL_IN_WD / (BOOTH2_TRA_WD - 1);
  //*** INPUT/OUTPUT *************************************************************
  // global
  input clk;
  input rstn;
  input val_i;
  // dat_i
  input [MUL_IN_WD                       - 1 : 0] ai;
  input [MUL_IN_WD                       - 1 : 0] bi;
  // dat_o
  output reg val_o;
  output  reg [BOOTH2_TRA_NUM * PRODCUT_OUT_WD - 1 : 0] ppo;
  output  reg [BOOTH2_TRA_NUM                  - 1 : 0] so;
  output  reg [BOOTH2_TRA_NUM                  - 1 : 0] eo;
  //*** WIRE/REG *****************************************************************
  wire [                          MUL_IN_WD : 0] b_w;
  wire [BOOTH2_TRA_NUM * PRODCUT_OUT_WD - 1 : 0] pp_w;
  wire [BOOTH2_TRA_NUM                  - 1 : 0] s_w;
  wire [BOOTH2_TRA_NUM                  - 1 : 0] e_w;
  // genvar
  genvar gvIdx;
  //*** MAIN BODY ****************************************************************
  // output
  // val_o
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      val_o <= 1'b0;
    end else begin
      val_o <= val_i;
    end
  end
  // ppo
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      ppo <= 'd0;
    end else begin
      if (val_i) begin
        ppo <= pp_w;
      end
    end
  end
  // so
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      so <= 'd0;
    end else begin
      if (val_i) begin
        so <= s_w;
      end
    end
  end
  // eo
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      eo <= 'd0;
    end else begin
      if (val_i) begin
        eo <= e_w;
      end
    end
  end

