    reg [3:0] delay;
    reg [ADDR_WIDTH-1:0] last_r_addr;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            integer i;
            for (i = 0; i < MEMORY_SIZE; i = i + 1) begin
                mm[i] <= {BLOCK_SIZE{1'b0}};
            end
            q <= {BLOCK_SIZE{1'b0}};
            block_ready <= 1'b0;
            delay <= 4'd0;
            last_r_addr <= {ADDR_WIDTH{1'b0}};
        end else begin
            if (we) begin
                mm[w_addr] <= block;
            end

            if (r_addr != last_r_addr) begin
                delay <= 4'd1;
                block_ready <= 1'b0;
                last_r_addr <= r_addr;
            end else if (delay > 4'd0 && delay < 4'd10) begin
                delay <= delay + 4'd1;
            end else if (delay == 4'd10) begin
                q <= mm[r_addr];
                block_ready <= 1'b1;
                delay <= 4'd0;
            end
        end
    end

