        .BLOCK_SIZE(BLOCK_SIZE),
        .MEMORY_SIZE(MEMORY_SIZE),
        .ADDR_WIDTH(ADDR_WIDTH)
    ) dut (
        .clk(clk),
        .rst(rst),
        .we(we),
        .r_addr(r_addr),
        .w_addr(w_addr),
        .block(block),
        .q(q),
        .block_ready(block_ready),
        .fifo_full(fifo_full)
    );

    always #5 clk = ~clk;

    initial begin
        clk = 0;
        rst = 1;
        we = 0;
        r_addr = 0;
        w_addr = 0;
        block = 0;

        #10 rst = 0;

        // Write to address 0x3
        #10 we = 1;
        w_addr = 10'h3;
        block = {BLOCK_SIZE{1'b1}};
        #10 we = 0;

        // Write to address 0x4
        #10 we = 1;
        w_addr = 10'h4;
